// Color scale generator
function getColorForValue(value, min, max, colorScheme) {
  if (value === null || value === undefined) return '#e5e7eb';

  const schemes = {
    teal: ['#ccfbf1', '#99f6e4', '#5eead4', '#2dd4bf', '#14b8a6', '#0d9488', '#0f766e'],
    blue: ['#dbeafe', '#bfdbfe', '#93c5fd', '#60a5fa', '#3b82f6', '#2563eb', '#1d4ed8'],
    red: ['#fee2e2', '#fecaca', '#fca5a5', '#f87171', '#ef4444', '#dc2626', '#b91c1c'],
    green: ['#d1fae5', '#a7f3d0', '#6ee7b7', '#34d399', '#10b981', '#059669', '#047857'],
    amber: ['#fef3c7', '#fde68a', '#fcd34d', '#fbbf24', '#f59e0b', '#d97706', '#b45309']
  };

  const colors = schemes[colorScheme] || schemes.teal;
  const normalized = (value - min) / (max - min);
  const index = Math.min(Math.floor(normalized * colors.length), colors.length - 1);
  return colors[Math.max(0, index)];
}

export default function MalaysiaMap({ onStateClick, onStateHover }) {
  const [selectedMetric, setSelectedMetric] = useState('graduateEmploymentRate');
  const [hoveredState, setHoveredState] = useState(null);
  const [tooltipPosition, setTooltipPosition] = useState({ x: 0, y: 0 });
  const [selectedState, setSelectedState] = useState(null);

  // Listen for state selection from StateList component
  useEffect(() => {
    const handleExternalStateClick = (event) => {
      const { stateName } = event.detail;
      setSelectedState(stateName);
    };

    window.addEventListener('stateClick', handleExternalStateClick);
    return () => window.removeEventListener('stateClick', handleExternalStateClick);
  }, []);

  // Merge summary data with graduate data
  const mergedData = useMemo(() => {
    const merged = {};
    Object.keys(summaryData).forEach(state => {
      merged[state] = {
        ...summaryData[state],
        ...graduateData[state]
      };
    });
    return merged;
  }, []);

  // Get metric values for all states
  const metricValues = Object.entries(mergedData).map(([state, data]) => ({
    state,
    value: data[selectedMetric]
  })).filter(d => d.value !== null && d.value !== undefined);

  const min = Math.min(...metricValues.map(d => d.value));
  const max = Math.max(...metricValues.map(d => d.value));

  // Grouped metrics configuration
  const metricGroups = {
    'wellbeing': {
      label: 'Well-Being (MyWI)',
      metrics: {
        'mywi_overall': { label: 'MyWI Overall Index', scheme: 'teal', format: (v) => v?.toFixed(1) },
        'mywi_economic': { label: 'MyWI Economic', scheme: 'blue', format: (v) => v?.toFixed(1) },
        'mywi_social': { label: 'MyWI Social', scheme: 'green', format: (v) => v?.toFixed(1) },
        'mywi_environmental': { label: 'MyWI Environmental', scheme: 'green', format: (v) => v?.toFixed(1) }
      }
    },
    'education_employment': {
      label: 'Education & Employment',
      metrics: {
        'mywi_education': { label: 'MyWI Education Component', scheme: 'blue', format: (v) => v?.toFixed(1) },
        'mywi_working_life': { label: 'MyWI Working Life Component', scheme: 'teal', format: (v) => v?.toFixed(1) },
        'graduateUnemploymentRate': { label: 'Graduate Unemployment Rate', scheme: 'red', format: (v) => `${v?.toFixed(1)}%` },
        'graduateEmploymentRate': { label: 'Graduate Employment Rate', scheme: 'green', format: (v) => `${v?.toFixed(1)}%` },
        'unemployment_rate': { label: 'Overall Unemployment Rate', scheme: 'red', format: (v) => `${v?.toFixed(1)}%` },
        'participation_rate': { label: 'Labour Force Participation', scheme: 'green', format: (v) => `${v?.toFixed(1)}%` },
        'school_completion_rate': { label: 'School Completion Rate', scheme: 'blue', format: (v) => `${v?.toFixed(1)}%` }
      }
    },
    'economic': {
      label: 'Economic Context',
      metrics: {
        'gdp_total': { label: 'GDP Total', scheme: 'blue', format: (v) => `RM ${v?.toFixed(2)}B` },
        'mean_income': { label: 'Mean Household Income', scheme: 'teal', format: (v) => `RM ${v?.toLocaleString()}` },
        'mywi_income_distribution': { label: 'MyWI Income & Distribution', scheme: 'teal', format: (v) => v?.toFixed(1) },
        'gini': { label: 'Gini Coefficient', scheme: 'amber', format: (v) => v?.toFixed(3) }
      }
    }
  };

  // Flatten all metrics for easy lookup
  const metricConfig = {};
  Object.values(metricGroups).forEach(group => {
    Object.assign(metricConfig, group.metrics);
  });

  const currentConfig = metricConfig[selectedMetric] || metricConfig.unemployment_rate;

  const handleMouseEnter = (state) => {
    setHoveredState(state);
    // Emit event for StateInfoPanel
    window.dispatchEvent(new CustomEvent('stateHover', {
      detail: { stateName: state }
    }));
  };

  const handleMouseLeave = () => {
    setHoveredState(null);
    // Clear hover event
    window.dispatchEvent(new CustomEvent('stateHover', {
      detail: { stateName: selectedState }
    }));
  };

  const handleStateClick = (state) => {
    setSelectedState(state);

    // Dispatch custom event for state click
    window.dispatchEvent(new CustomEvent('stateClick', {
      detail: { stateName: state, stateData: mergedData[state] }
    }));

    if (onStateClick) {
      onStateClick(state, mergedData[state]);
    }
  };

  return (
    <div className="w-full">
      <svg
        viewBox="0 0 750 300"
        style={{ width: '100%', height: '400px' }}
      >
          <g transform="scale(1.0)">
          {/* Peninsular Malaysia background */}
          <rect x="0" y="30" width="300" height="270" fill="#f9fafb" opacity="0.2" rx="8" />
          {/* East Malaysia background */}
          <rect x="300" y="50" width="450" height="200" fill="#f9fafb" opacity="0.2" rx="8" />

          {/* State paths */}
          {Object.entries(statePaths).map(([state, path]) => {
            const stateData = mergedData[state];
            const value = stateData?.[selectedMetric];
            const fillColor = getColorForValue(value, min, max, currentConfig.scheme);

            const isSelected = selectedState === state;

            return (
              <path
                key={state}
                d={path}
                fill={fillColor}
                stroke={isSelected ? "#0d9488" : "#1f2937"}
                strokeWidth={isSelected ? "3" : "1.5"}
                className={`transition-all duration-300 cursor-pointer hover:opacity-80 ${!isSelected && 'hover:stroke-[3]'}`}
                style={{
                  filter: isSelected ? 'drop-shadow(0 4px 6px rgba(0, 0, 0, 0.3))' : 'none'
                }}
                onMouseEnter={() => handleMouseEnter(state)}
                onMouseLeave={handleMouseLeave}
                onClick={() => handleStateClick(state)}
                data-state={state}
              />
            );
          })}

          {/* State labels */}
          {Object.entries(statePaths).map(([state]) => {
            // Label positions for geographic map
            const labelPositions = {
              'Perlis': { x: 95, y: 50 },
              'Kedah': { x: 110, y: 80 },
              'Pulau Pinang': { x: 100, y: 105 },
              'Perak': { x: 125, y: 135 },
              'Kelantan': { x: 175, y: 95 },
              'Terengganu': { x: 220, y: 120 },
              'Pahang': { x: 185, y: 175 },
              'Selangor': { x: 145, y: 195 },
              'W.P. Kuala Lumpur': { x: 160, y: 200 },
              'W.P. Putrajaya': { x: 160, y: 207 },
              'Negeri Sembilan': { x: 185, y: 225 },
              'Melaka': { x: 188, y: 240 },
              'Johor': { x: 225, y: 265 },
              'Sabah': { x: 670, y: 115 },
              'Sarawak': { x: 470, y: 215 },
              'W.P. Labuan': { x: 560, y: 100 }
            };

            const pos = labelPositions[state];
            if (!pos) return null;

            // Shorter labels for small territories
            const displayName = state === 'W.P. Kuala Lumpur' ? 'KL' :
                               state === 'W.P. Putrajaya' ? 'PJ' :
                               state === 'W.P. Labuan' ? 'LB' :
                               state === 'Pulau Pinang' ? 'Penang' :
                               state === 'Negeri Sembilan' ? 'N.S.' :
                               state;

            return (
              <text
                key={`label-${state}`}
                x={pos.x}
                y={pos.y}
                textAnchor="middle"
                className="text-xs font-medium fill-gray-700 pointer-events-none select-none"
                style={{ fontSize: state.startsWith('W.P.') ? '8px' : '10px' }}
              >
                {displayName}
              </text>
            );
          })}
          </g>
      </svg>

      {/* Color Legend */}
      <ColorLegend
        min={min}
        max={max}
        colorScheme={currentConfig.scheme}
        label={currentConfig.label}
        format={currentConfig.format}
      />
    </div>
  );
}
